<?php
namespace App\Services\Customers; use App\Models\Customers\Customer; use App\Models\Customers\CustomerInsightSnapshot; use App\Models\Customers\CustomerReturnSummary; use App\Models\Customers\CustomerSetting; use App\Models\User; use App\Services\AuditLogger;
class CustomerInsightService { public function __construct(private readonly AuditLogger $audit,private readonly CustomerEventService $events){} public function calculate(Customer $customer,?User $user=null):CustomerInsightSnapshot{$settings=CustomerSetting::firstOrCreate(['company_id'=>$customer->company_id]);$days=$customer->last_purchase_at?->diffInDays(now());$average=$customer->total_orders_count?(float)$customer->total_purchase_amount/$customer->total_orders_count:0;$returnRate=$customer->total_purchase_amount>0?(float)$customer->total_return_amount/$customer->total_purchase_amount*100:0;$frequent=$customer->total_returns_count>=$settings->frequent_return_threshold_count;$inactive=$days!==null&&$days>=$settings->inactive_customer_days;$lost=$customer->status==='lost'||($days!==null&&$days>=$settings->lost_customer_days);$tier=$customer->loyaltyAccount?->tier;$value=min(100,round(min(55,$customer->total_purchase_amount/1000)+min(20,$customer->total_orders_count*2)+min(15,$average/500)+(in_array($tier,['gold','platinum','vip'])?10:0),2));$retention=$lost?100:($inactive?75:($days===null?30:min(60,$days/$settings->inactive_customer_days*60)));$recentReturn=$customer->last_return_at&&$customer->last_return_at->diffInDays(now())<=90?15:0;$returnRisk=min(100,round($customer->total_returns_count*12+$returnRate+$recentReturn,2));$segment=$lost?'Lost':($frequent?'Frequent Returner':($tier==='vip'||$customer->customer_type==='vip'?'VIP':($customer->customer_type==='wholesale'?'Wholesale':($inactive?'Inactive':'Active'))));$snapshot=CustomerInsightSnapshot::updateOrCreate(['company_id'=>$customer->company_id,'customer_id'=>$customer->id],['total_purchase_amount'=>$customer->total_purchase_amount,'total_orders_count'=>$customer->total_orders_count,'average_order_value'=>$average,'last_purchase_at'=>$customer->last_purchase_at,'days_since_last_purchase'=>$days,'total_return_amount'=>$customer->total_return_amount,'total_returns_count'=>$customer->total_returns_count,'return_rate'=>$returnRate,'loyalty_points_balance'=>$customer->loyalty_points_balance,'customer_value_score'=>$value,'retention_risk_score'=>$retention,'return_risk_score'=>$returnRisk,'segment_label'=>$segment,'is_top_customer'=>false,'is_inactive_90_days'=>$inactive,'is_lost_customer'=>$lost,'is_frequent_returner'=>$frequent,'calculated_at'=>now(),'notes'=>'Rule-based customer intelligence; POS sales and return history will replace demo/foundation values when available.']);CustomerReturnSummary::updateOrCreate(['company_id'=>$customer->company_id,'customer_id'=>$customer->id],['return_count'=>$customer->total_returns_count,'return_amount'=>$customer->total_return_amount,'last_return_at'=>$customer->last_return_at,'frequent_return_score'=>$returnRisk,'is_frequent_returner'=>$frequent,'calculated_at'=>now(),'reason_summary'=>['source'=>'Demo/foundation return behavior until POS returns are connected.']]);if($user){$this->audit->record('customer.insight.recalculated',$customer,'Customer insight recalculated');foreach([['customer.inactive.detected',$inactive],['customer.lost.detected',$lost],['customer.frequent_returner.detected',$frequent]] as [$event,$yes])if($yes)$this->events->dispatch($event,$user,$customer,['customer_name'=>$customer->display_name]);}return $snapshot;} public function refreshCompany(int $companyId,?User $user=null):void{Customer::query()->where('company_id',$companyId)->each(fn(Customer $c)=>$this->calculate($c,$user));$top=CustomerInsightSnapshot::query()->where('company_id',$companyId)->orderByDesc('total_purchase_amount')->limit(10)->pluck('id');CustomerInsightSnapshot::query()->where('company_id',$companyId)->update(['is_top_customer'=>false]);CustomerInsightSnapshot::query()->whereIn('id',$top)->update(['is_top_customer'=>true]);} }
